    let r;
    {
        let x = 5;
        r = &x; // r would dangle after x is dropped!
    }
    // x is dropped here
    println!("{}", r); // would use freed memory
}

fn longest<'a>(x: &'a str, y: &'a str) -> &'a str {
    if x.len() > y.len() { x } else { y }
}

fn main() {
    let s1 = String::from("long string");
    let result;
    {
        let s2 = String::from("xyz");
        result = longest(s1.as_str(), s2.as_str());
        println!("{}", result);
    }
}

// These all have lifetimes — elision handles them
fn first_word(s: &str) -> &str {
    match s.find(' ') {
        Some(i) => &s[..i],
        None    => s,
    }
}

fn main() {
    let s = String::from("hello world");
    println!("{}", first_word(&s));
}

struct Important<'a> {
    text: &'a str,
}

impl<'a> Important<'a> {
    fn display(&self) {
        println!("Important: {}", self.text);
    }
}

fn main() {
    let text = String::from("Don't forget this!");
    let excerpt = Important { text: &text };
    excerpt.display();
}

fn announce<'a, 'b>(announcement: &'a str, name: &'b str) -> &'a str {
    println!("Attention {}!", name);
    announcement
}

fn main() {
    let ann = String::from("Sale today!");
    let result;
    {
        let name = String::from("Alice");
        result = announce(&ann, &name);
    }
    println!("{}", result);
}

fn static_str() -> &'static str {
    "I live forever in the binary"
}

fn main() {
    let s: &'static str = "hello world";
    let r = static_str();
    println!("{} | {}", s, r);
}

fn print_ref<'a, T>(t: &'a T)
where
    T: std::fmt::Display + 'a,
{
    println!("{}", t);
}

fn main() {
    let n = 42;
    let s = "hello";
    print_ref(&n);
    print_ref(&s);
}

fn summary<'a>(long: &'a str, short: &'a str) -> &'a str {
    if long.len() > short.len() { long } else { short }
}

fn main() {
    let a = String::from("I am the longer string");
    let b = String::from("short");
    let result = summary(&a, &b);
    println!("longer: {}", result);
}
